import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private const val BASE_URL_DEV = "https://api.example.com/dev/users/"
    private const val BASE_URL_STAGING = "https://api.example.com/staging/users/"
    private const val BASE_URL_PROD = "https://api.example.com/prod/users/"

    private fun createOkHttpClient(authToken: String): OkHttpClient {
        return OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(authToken))
            .build()
    }

    private fun createRetrofit(client: OkHttpClient, baseUrl: String): Retrofit {
        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    fun provideUserService(env: Environment, authToken: String): UserService {
        val client = createOkHttpClient(authToken)
        val retrofit = when (env) {
            Environment.DEV -> createRetrofit(client, BASE_URL_DEV)
            Environment.STAGING -> createRetrofit(client, BASE_URL_STAGING)
            Environment.PROD -> createRetrofit(client, BASE_URL_PROD)
        }
        return retrofit.create(UserService::class.java)
    }

    private class AuthInterceptor(private val authToken: String) : Interceptor {
        override fun intercept(chain: Interceptor.Chain): okhttp3.Response {
            val originalRequest = chain.request()
            val newRequest = originalRequest.newBuilder()
                .header("Authorization", "Bearer $authToken")
                .build()
            return chain.proceed(newRequest)
        }
    }

    enum class Environment {
        DEV,
        STAGING,
        PROD
    }
}

interface UserService {
    @GET(".")
    suspend fun getUserProfiles(): List<UserProfile>
}

data class UserProfile(
    val id: Int,
